def exponential_search(arr, x):
    n = len(arr)

    if n == 0:
        return -1

    if arr[0] == x:
        return 0

    # Adım 1: İkili arama için aralığı bulmak için üstel olarak ilerle
    bound = 1
    while bound < n and arr[bound] < x:
        bound *= 2

    # Adım 2: Belirlenen aralıkta ikili arama yap
    # Arama aralığı [bound // 2, min(bound, n - 1)]
    left = bound // 2
    right = min(bound, n - 1)

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] < x:
            left = mid + 1
        else:  # arr[mid] > x
            right = mid - 1

    return -1
